```java
@Entity @Table(name="products")
@org.hibernate.annotations.Where(clause="deleted = false")  // soft delete filter
public class Product {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    @Column(nullable=false) private String name;
    @Column(nullable=false) private double price;
    private boolean deleted = false;  // soft delete flag

    // @ManyToMany — safe cascades only:
    @ManyToMany(cascade={CascadeType.PERSIST, CascadeType.MERGE})
    @JoinTable(
        name="product_categories",
        joinColumns=@JoinColumn(name="product_id"),
        inverseJoinColumns=@JoinColumn(name="category_id")
    )
    private Set<Category> categories = new HashSet<>();

    // @Embedded warehouse address:
    @Embedded
    private WarehouseAddress warehouseAddress;

    // @ElementCollection tags:
    @ElementCollection
    @CollectionTable(name="product_tags", joinColumns=@JoinColumn(name="product_id"))
    @Column(name="tag")
    private Set<String> tags = new HashSet<>();

    // Helper methods (bidirectional maintenance):
    public void addCategory(Category cat) {
        categories.add(cat);
        cat.getProducts().add(this);
    }
    public void removeCategory(Category cat) {
        categories.remove(cat);
        cat.getProducts().remove(this);
    }

    // Soft delete:
    public void softDelete() { this.deleted = true; }

    // Constructor, getters...
    protected Product() {}
    public Product(String name, double price) { this.name=name; this.price=price; }
    public String getId()       { return id; }
    public String getName()     { return name; }
    public Set<Category> getCategories() { return categories; }
    public Set<String> getTags() { return tags; }
}
```

