```java
@DataJpaTest
class ProductCategoryTest {
    @Autowired TestEntityManager testEm;
    @Autowired ProductRepository repo;

    @Test void addCategory_bothSidesLinked() {
        Category elec = testEm.persistAndFlush(new Category("Electronics"));
        Product phone = new Product("iPhone 15", 89999);
        phone.addCategory(elec);
        phone.getTags().add("5G"); phone.getTags().add("Smartphone");
        phone.setWarehouseAddress(new WarehouseAddress("Mumbai","400001","MH"));
        Product saved = repo.save(phone);
        testEm.clear();

        Product loaded = repo.findById(saved.getId()).orElseThrow();
        assertEquals(1, loaded.getCategories().size());
        assertEquals("Electronics", loaded.getCategories().iterator().next().getName());
        assertEquals(2, loaded.getTags().size());
        assertEquals("Mumbai", loaded.getWarehouseAddress().getCity());
    }

    @Test void softDelete_hiddenFromFindAll() {
        Product p = repo.save(new Product("Widget", 99));
        testEm.clear();
        p = repo.findById(p.getId()).orElseThrow();
        p.softDelete();
        repo.save(p);
        testEm.clear();

        assertEquals(0, repo.findAll().size());  // @Where filters deleted=true
    }
}
```

